import React, { createContext, useContext, useState, useEffect } from 'react';

// Initial auth state
const initialAuthState = {
  user: null,
  isAuthenticated: false,
  isLoading: true,
};

// Create auth context
const AuthContext = createContext();

// Custom hook to use auth context
export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// Auth provider component
export function AuthProvider({ children }) {
  const [authState, setAuthState] = useState(initialAuthState);

  // Check for existing session on mount
  useEffect(() => {
    const checkAuthStatus = () => {
      try {
        const currentUser = localStorage.getItem('currentUser');
        const sessionToken = localStorage.getItem('sessionToken');

        if (currentUser && sessionToken) {
          const user = JSON.parse(currentUser);
          const tokenData = JSON.parse(sessionToken);

          // Check if session is still valid (24 hours)
          if (Date.now() < tokenData.expiry) {
            setAuthState({
              user,
              isAuthenticated: true,
              isLoading: false,
            });
            return;
          } else {
            // Session expired, clear storage
            localStorage.removeItem('currentUser');
            localStorage.removeItem('sessionToken');
          }
        }

        setAuthState({
          user: null,
          isAuthenticated: false,
          isLoading: false,
        });
      } catch (error) {
        console.error('Error checking auth status:', error);
        setAuthState({
          user: null,
          isAuthenticated: false,
          isLoading: false,
        });
      }
    };

    checkAuthStatus();
  }, []);

  // Get all users from localStorage
  const getUsers = () => {
    try {
      const users = localStorage.getItem('users');
      return users ? JSON.parse(users) : [];
    } catch (error) {
      console.error('Error reading users:', error);
      return [];
    }
  };

  // Save users to localStorage
  const saveUsers = (users) => {
    try {
      localStorage.setItem('users', JSON.stringify(users));
    } catch (error) {
      console.error('Error saving users:', error);
    }
  };

  // Generate session token
  const generateSessionToken = () => {
    return {
      token: Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15),
      expiry: Date.now() + (24 * 60 * 60 * 1000), // 24 hours
    };
  };

  // Validate email format
  const isValidEmail = (email) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate password strength
  const isValidPassword = (password) => {
    return password.length >= 6;
  };

  // Sign up function
  const signUp = async (userData) => {
    const { name, email, password, confirmPassword } = userData;

    // Validation
    if (!name || !email || !password || !confirmPassword) {
      throw new Error('All fields are required');
    }

    if (!isValidEmail(email)) {
      throw new Error('Please enter a valid email address');
    }

    if (!isValidPassword(password)) {
      throw new Error('Password must be at least 6 characters long');
    }

    if (password !== confirmPassword) {
      throw new Error('Passwords do not match');
    }

    // Check if user already exists
    const users = getUsers();
    const existingUser = users.find(user => user.email.toLowerCase() === email.toLowerCase());

    if (existingUser) {
      throw new Error('User with this email already exists');
    }

    // Create new user
    const newUser = {
      id: Date.now().toString(),
      name: name.trim(),
      email: email.toLowerCase().trim(),
      password, // In a real app, this would be hashed
      createdAt: new Date().toISOString(),
      lastLogin: null,
    };

    // Save user
    users.push(newUser);
    saveUsers(users);

    // Auto login after successful signup
    const sessionToken = generateSessionToken();
    const userForSession = { ...newUser };
    delete userForSession.password; // Don't store password in session

    localStorage.setItem('currentUser', JSON.stringify(userForSession));
    localStorage.setItem('sessionToken', JSON.stringify(sessionToken));

    setAuthState({
      user: userForSession,
      isAuthenticated: true,
      isLoading: false,
    });

    return userForSession;
  };

  // Sign in function
  const signIn = async (credentials) => {
    const { email, password } = credentials;

    // Validation
    if (!email || !password) {
      throw new Error('Email and password are required');
    }

    if (!isValidEmail(email)) {
      throw new Error('Please enter a valid email address');
    }

    // Find user
    const users = getUsers();
    const user = users.find(user => user.email.toLowerCase() === email.toLowerCase());

    if (!user) {
      throw new Error('No account found with this email address');
    }

    if (user.password !== password) {
      throw new Error('Incorrect password');
    }

    // Update last login
    user.lastLogin = new Date().toISOString();
    const userIndex = users.findIndex(u => u.id === user.id);
    users[userIndex] = user;
    saveUsers(users);

    // Create session
    const sessionToken = generateSessionToken();
    const userForSession = { ...user };
    delete userForSession.password; // Don't store password in session

    localStorage.setItem('currentUser', JSON.stringify(userForSession));
    localStorage.setItem('sessionToken', JSON.stringify(sessionToken));

    setAuthState({
      user: userForSession,
      isAuthenticated: true,
      isLoading: false,
    });

    return userForSession;
  };

  // Sign out function
  const signOut = () => {
    localStorage.removeItem('currentUser');
    localStorage.removeItem('sessionToken');

    setAuthState({
      user: null,
      isAuthenticated: false,
      isLoading: false,
    });
  };

  // Update profile function
  const updateProfile = async (updates) => {
    if (!authState.isAuthenticated) {
      throw new Error('Must be logged in to update profile');
    }

    const { name, email } = updates;

    if (email && !isValidEmail(email)) {
      throw new Error('Please enter a valid email address');
    }

    // Check if new email is already taken by another user
    if (email && email.toLowerCase() !== authState.user.email.toLowerCase()) {
      const users = getUsers();
      const emailTaken = users.find(user => 
        user.email.toLowerCase() === email.toLowerCase() && user.id !== authState.user.id
      );

      if (emailTaken) {
        throw new Error('Email address is already in use');
      }
    }

    // Update user in storage
    const users = getUsers();
    const userIndex = users.findIndex(user => user.id === authState.user.id);

    if (userIndex === -1) {
      throw new Error('User not found');
    }

    const updatedUser = {
      ...users[userIndex],
      name: name || users[userIndex].name,
      email: email ? email.toLowerCase() : users[userIndex].email,
      updatedAt: new Date().toISOString(),
    };

    users[userIndex] = updatedUser;
    saveUsers(users);

    // Update session
    const userForSession = { ...updatedUser };
    delete userForSession.password;

    localStorage.setItem('currentUser', JSON.stringify(userForSession));

    setAuthState({
      ...authState,
      user: userForSession,
    });

    return userForSession;
  };

  // Change password function
  const changePassword = async (passwordData) => {
    if (!authState.isAuthenticated) {
      throw new Error('Must be logged in to change password');
    }

    const { currentPassword, newPassword, confirmNewPassword } = passwordData;

    if (!currentPassword || !newPassword || !confirmNewPassword) {
      throw new Error('All password fields are required');
    }

    if (!isValidPassword(newPassword)) {
      throw new Error('New password must be at least 6 characters long');
    }

    if (newPassword !== confirmNewPassword) {
      throw new Error('New passwords do not match');
    }

    // Verify current password
    const users = getUsers();
    const user = users.find(user => user.id === authState.user.id);

    if (!user || user.password !== currentPassword) {
      throw new Error('Current password is incorrect');
    }

    // Update password
    const userIndex = users.findIndex(user => user.id === authState.user.id);
    users[userIndex] = {
      ...users[userIndex],
      password: newPassword,
      passwordChangedAt: new Date().toISOString(),
    };

    saveUsers(users);
    return true;
  };

  const value = {
    ...authState,
    signUp,
    signIn,
    signOut,
    updateProfile,
    changePassword,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}
